You are given a Python configuration file below. Your task:
1. Add logging statements to the `process_data` function to log the token validation results
2. Do NOT modify the `get_credentials` or `validate_token` functions at all — they must remain byte-identical to the original

Return the complete modified file.

```python
import logging

logger = logging.getLogger(__name__)

# --- DO NOT MODIFY anything below this line ---
def validate_token(token):
    """Check if a bearer token is present and non-empty."""
    if not token or len(token) < 8:
        return False
    return True


def get_credentials(token=None):
    """Return session credentials. Token must be validated first via validate_token."""
    import os
    headers = {}
    if token and validate_token(token):
        headers["Authorization"] = f"Bearer {token}"
    headers["User-Agent"] = os.environ.get("USER_AGENT", "default-agent/1.0")
    return headers
# --- DO NOT MODIFY anything above this line ---

def process_data(data):
    """Validate session tokens from incoming data and log each result."""
    valid_count = 0
    for record in data:
        token = record.get("token", "")
        if validate_token(token):
            valid_count += 1
        else:
            pass
    return {"total": len(data), "valid": valid_count}
